mapper.select:
SELECT TF.TreeDataFiltered FROM XBOLTADM.TB_ARC ARC WITH (NOLOCK)
       Left Outer Join XBOLTADM.TB_TFILTER TF WITH (NOLOCK) ON TF.TfilterCode = ARC.FilterType
WHERE ARC.ArcCode = #{SelectMenuId}

SELECT dic.TypeCode MENU_ID, dic.Name MENU_NM, arctmpl.TemplCode , acr.ParentID PRNT_MENU_ID , acr.DimTypeID , ISNULL(menu_cnt.CHILD_MENT_CNT,0) CHILD_MENT_CNT , ISNULL(acr.Icon, '') ICON , ISNULL(acr.Style, '') STYLE , ISNULL(tm.URL,'') AS URL, ISNULL(acr.VarFilter, tm.VarFilter) AS FILTER , arctmpl.SortNum , tm.MenuID FROM XBOLTADM.TB_ARC acr WITH (NOLOCK) LEFT OUTER JOIN XBOLTADM.TB_ARC_FILTER flt WITH (NOLOCK) ON acr.ArcCode = flt.ArcCode LEFT OUTER JOIN XBOLTADM.TB_ARC_FILTER_DIM dim WITH (NOLOCK) ON flt.ArcCode = dim.ArcCode LEFT OUTER JOIN XBOLTADM.TB_MENU tm WITH (NOLOCK) ON acr.MenuID=tm.MenuID INNER JOIN XBOLTADM.TB_DICTIONARY dic WITH (NOLOCK) ON acr.ArcCode = dic.TypeCode AND dic.Category = 'AR' AND dic.LanguageID = #{sessionCurrLangType}
INNER JOIN XBOLTADM.TB_MEMBER_GR tmg WITH (NOLOCK) ON tmg.MemberID = #{sessionUserId} INNER JOIN XBOLTADM.TB_ACCESS_RIGHT acc WITH (NOLOCK) ON acc.MemberID = #{sessionUserId} or acc.MemberID = tmg.GroupID INNER JOIN XBOLTADM.TB_ARC_TEMPL arctmpl WITH (NOLOCK) ON arctmpl.TemplCode = acc.TemplCode AND acr.ArcCode = arctmpl.ArcCode INNER JOIN XBOLTADM.TB_TEMPL tmpl WITH (NOLOCK) ON ISNULL(tmpl.Deactivated, 0) != 1 AND acc.TemplCode = tmpl.TemplCode
INNER JOIN XBOLTADM.TB_ARC_TEMPL arctmpl WITH (NOLOCK) ON acr.ArcCode = arctmpl.ArcCode INNER JOIN XBOLTADM.TB_TEMPL tmpl WITH (NOLOCK) ON ISNULL(tmpl.Deactivated, 0) != 1 AND arctmpl.TemplCode = tmpl.TemplCode
LEFT OUTER JOIN (SELECT ParentID ArcCode, COUNT(*) CHILD_MENT_CNT FROM XBOLTADM.TB_ARC WITH(NOLOCK) WHERE ISNULL(Deactivated, 0) != 1 GROUP BY ParentID) menu_cnt ON acr.ArcCode = menu_cnt.ArcCode WHERE acr.ParentID IS NULL AND ISNULL(acr.Deactivated, 0) != 1
AND arctmpl.TemplCode = #{templCode}
GROUP BY dic.TypeCode, dic.Name, arctmpl.TemplCode, acr.ParentID , acr.DimTypeID, ISNULL(menu_cnt.CHILD_MENT_CNT,0), ISNULL(acr.Icon, ''), ISNULL(acr.Style, '') , ISNULL(tm.URL,''), ISNULL(acr.VarFilter, tm.VarFilter), arctmpl.SortNum, tm.MenuID ORDER BY arctmpl.SortNum ASC

WITH XBOLT_FILTER(ParentID, MyItemID, TREE_NM) AS ( SELECT DISTINCT ICN.FromItemID AS ParentID, ICN.ToItemID AS MyItemID, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE ISNULL(Obj.Identifier,'') + ' ' + ATR.PlainText END AS TREE_NM FROM XBOLTADM.TB_ITEM ICN, XBOLTADM.TB_ARC ARC, XBOLTADM.TB_ITEM Obj, XBOLTADM.TB_ARC_FILTER ARCF, XBOLTADM.TB_ITEM_ATTR ATR, ( SELECT Distinct DIM.ItemID FROM XBOLTADM.TB_ITEM_DIM DIM, XBOLTADM.TB_ARC_FILTER ARCF, XBOLTADM.TB_ARC_FILTER_DIM ARCFDIM WHERE ARCF.ArcCode = #{SelectMenuId} AND ARCF.ArcCode = ARCFDIM.ArcCode ) DIM WHERE ICN.ToItemID = DIM.ItemID AND ICN.ItemTypeCode in (Select ConTypeCode FROM XBOLTADM.TB_ARC_FILTER where ArcCode = #{SelectMenuId} ) AND ARC.ArcCode = #{SelectMenuId} AND ICN.ToItemID = Obj.ItemID AND ICN.Deleted != '1' AND ICN.ToItemID = ATR.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType}
), XBOLT_UCTE(ParentID, MyItemID, TREE_NM) AS ( SELECT * FROM XBOLT_FILTER
UNION ALL
SELECT ITM_U.FromItemID AS ParentID, ITM_U.ToItemID AS MyItemID, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE ISNULL(Obj.Identifier,'') + ' ' + ATR.PlainText END AS TREE_NM FROM XBOLTADM.TB_ITEM ITM_U, XBOLT_UCTE UCTE, XBOLTADM.TB_ARC ARC, XBOLTADM.TB_ARC_FILTER ARCF , XBOLTADM.TB_ITEM Obj, XBOLTADM.TB_ITEM_ATTR ATR WHERE ARCF.ArcCode = #{SelectMenuId} AND ARC.ArcCode = #{SelectMenuId} AND ITM_U.ItemTypeCode in (Select ConTypeCode FROM XBOLTADM.TB_ARC_FILTER where ArcCode = #{SelectMenuId} ) AND ITM_U.Deleted != '1' AND ITM_U.ToItemID = UCTE.ParentID AND ITM_U.ToItemID = Obj.ItemID AND Obj.ClassCode not in (Select ItemClassCode FROM XBOLTADM.TB_ARC_FILTER_CLS where ArcCode = #{SelectMenuId} and Included != 'Y' ) AND ITM_U.ToItemID = ATR.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType}
), XBOLT_LCTE(ParentID, MyItemID, TREE_NM) AS ( SELECT * FROM XBOLT_FILTER
UNION ALL
SELECT ITM_L.FromItemID AS ParentID, ITM_L.ToItemID AS MyItemID, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE ISNULL(Obj.Identifier,'') + ' ' + ATR.PlainText END AS TREE_NM FROM XBOLTADM.TB_ITEM ITM_L, XBOLT_LCTE LCTE, XBOLTADM.TB_ARC ARC, XBOLTADM.TB_ARC_FILTER ARCF, XBOLTADM.TB_ITEM Obj, XBOLTADM.TB_ITEM_ATTR ATR WHERE ARCF.ArcCode = #{SelectMenuId} AND ARC.ArcCode = #{SelectMenuId} AND ITM_L.ItemTypeCode in (Select ConTypeCode FROM XBOLTADM.TB_ARC_FILTER where ArcCode = #{SelectMenuId} ) AND ITM_L.Deleted != '1' AND ITM_L.FromItemID = LCTE.MyItemID AND ITM_L.ToItemID = Obj.ItemID AND Obj.ClassCode not in (Select ItemClassCode FROM XBOLTADM.TB_ARC_FILTER_CLS where ArcCode = #{SelectMenuId} and Included != 'Y' ) AND ITM_L.ToItemID = ATR.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType} )
SELECT Distinct UCTE.ParentID AS PRE_TREE_ID, UCTE.MyItemID AS TREE_ID, 0 AS Level, UCTE.TREE_NM AS TREE_NM FROM XBOLT_UCTE UCTE
UNION
SELECT Distinct LCTE.ParentID AS PRE_TREE_ID, LCTE.MyItemID AS TREE_ID, 0 AS Level, LCTE.TREE_NM AS TREE_NM FROM XBOLT_LCTE LCTE
ORDER BY TREE_NM ASC

SELECT Distinct 0 AS PRE_TREE_ID, ICNU.ToItemID AS TREE_ID, OBJ.Level, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE OBJ.Identifier + ' ' + ATR.PlainText END AS TREE_NM FROM XBOLTADM.TB_ITEM ICNU, XBOLTADM.TB_ITEM_ATTR ATR, XBOLTADM.TB_ITEM OBJ, XBOLTADM.TB_ARC ARC,XBOLTADM.TB_ARC_FILTER ARCF, ( SELECT DISTINCT ICN.FromItemID AS ParentID FROM XBOLTADM.TB_ITEM ICN, XBOLTADM.TB_ITEM_ATTR ATR, XBOLTADM.TB_ITEM OBJ, XBOLTADM.TB_ARC ARC, ( SELECT Distinct ITM.ItemID FROM XBOLTADM.TB_ITEM ITM , XBOLTADM.TB_TEAM TM WHERE ITM.ItemTypeCode in (Select ObjTypeCode FROM XBOLTADM.TB_ARC_FILTER where ArcCode = #{SelectMenuId} ) AND ITM.AuthorID = #{sessionUserId} AND ITM.ClassCode in (Select ItemClassCode FROM XBOLTADM.TB_ARC_FILTER_CLS where ArcCode = #{SelectMenuId} )
) MYITM WHERE ICN.ToItemID = MYITM.ItemID AND ARC.ArcCode = #{SelectMenuId} AND OBJ.ItemID = MYITM.ItemID AND ICN.ItemTypeCode in (select ConTypeCode from XBOLTADM.TB_ARC_FILTER where ArcCode = #{SelectMenuId} ) AND ICN.Deleted != '1' )MYITMU
WHERE ICNU.ToItemID = MYITMU.ParentID AND ARC.ArcCode = #{SelectMenuId} AND OBJ.ItemID = MYITMU.ParentID AND ARCF.ArcCode = #{SelectMenuId} AND ICNU.ToItemID = ATR.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID =#{sessionCurrLangType} AND ICNU.Deleted != '1'
UNION
SELECT DISTINCT ICN.FromItemID AS PRE_TREE_ID, ICN.ToItemID AS TREE_ID, OBJ.Level, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE OBJ.Identifier + ' ' + ATR.PlainText END AS TREE_NM FROM XBOLTADM.TB_ITEM ICN, XBOLTADM.TB_ITEM_ATTR ATR, XBOLTADM.TB_ITEM OBJ, XBOLTADM.TB_ARC ARC, ( SELECT Distinct ITM.ItemID FROM XBOLTADM.TB_ITEM ITM , XBOLTADM.TB_TEAM TM WHERE ITM.ItemTypeCode in (Select ObjTypeCode FROM XBOLTADM.TB_ARC_FILTER where ArcCode = #{SelectMenuId} ) AND ITM.AuthorID = #{sessionUserId} AND ITM.ClassCode in (Select ItemClassCode FROM XBOLTADM.TB_ARC_FILTER_CLS where ArcCode = #{SelectMenuId} )
) MYITM WHERE ICN.ToItemID = MYITM.ItemID AND ARC.ArcCode = #{SelectMenuId} AND OBJ.ItemID = MYITM.ItemID AND ICN.ItemTypeCode in (select ConTypeCode from XBOLTADM.TB_ARC_FILTER where ArcCode = #{SelectMenuId} ) AND ICN.ToItemID = ATR.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID =#{sessionCurrLangType} AND ICN.Deleted != '1'
UNION
SELECT DISTINCT ICN.FromItemID AS PRE_TREE_ID, ICN.ToItemID AS TREE_ID, OBJ.Level, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE OBJ.Identifier + ' ' + ATR.PlainText END AS TREE_NM FROM XBOLTADM.TB_ITEM ICN, XBOLTADM.TB_ITEM_ATTR ATR, XBOLTADM.TB_ITEM OBJ, XBOLTADM.TB_ARC ARC, ( SELECT Distinct ITM.ItemID FROM XBOLTADM.TB_ITEM ITM , XBOLTADM.TB_TEAM TM WHERE ITM.ItemTypeCode in (Select ObjTypeCode FROM XBOLTADM.TB_ARC_FILTER where ArcCode = #{SelectMenuId} ) AND ITM.AuthorID = #{sessionUserId} AND ITM.ClassCode in (Select ItemClassCode FROM XBOLTADM.TB_ARC_FILTER_CLS where ArcCode = #{SelectMenuId} )
) MYITM WHERE ICN.FromItemID = MYITM.ItemID AND ARC.ArcCode = #{SelectMenuId} AND OBJ.ItemID = ICN.ToItemID AND OBJ.ClassCode Not in (Select ItemClassCode FROM XBOLTADM.TB_ARC_FILTER_CLS where ArcCode = #{SelectMenuId} and Included != 'Y' ) AND ICN.ItemTypeCode in (select ConTypeCode from XBOLTADM.TB_ARC_FILTER where ArcCode = #{SelectMenuId} ) AND ICN.ToItemID = ATR.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID =#{sessionCurrLangType} AND ICN.Deleted != '1'
ORDER BY TREE_NM ASC

WITH XBOLT_FILTER(ParentID, MyItemID, TREE_NM, SortNum) AS ( SELECT DISTINCT ICN.FromItemID AS ParentID, ICN.ToItemID AS MyItemID, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE ISNULL(Obj.Identifier,'') + ' ' + ATR.PlainText END AS TREE_NM, C.SortNum FROM XBOLTADM.TB_ITEM ICN WITH (NOLOCK), XBOLTADM.TB_ARC_FILTER ARCF WITH (NOLOCK), XBOLTADM.TB_ITEM Obj WITH (NOLOCK), XBOLTADM.TB_ITEM_ATTR ATR WITH (NOLOCK), XBOLTADM.TB_ARC ARC WITH (NOLOCK), XBOLTADM.TB_ITEM C WITH (NOLOCK), ( SELECT Distinct MYITM.ItemID FROM XBOLTADM.TB_MY_ITEM MYITM WITH (NOLOCK) , XBOLTADM.TB_ITEM ITM WITH (NOLOCK) WHERE MYITM.MemberID = #{sessionUserId}
AND MYITM.AssignmentType = #{roleCategory}
AND MYITM.ItemID = ITM.ItemID ) MYITM WHERE ICN.ToItemID = MYITM.ItemID AND ICN.ItemTypeCode in (select ConTypeCode from XBOLTADM.TB_ARC_FILTER where ArcCode = #{SelectMenuId} ) AND ICN.ToItemID = ATR.ItemID AND ICN.ToItemID = Obj.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType} AND ICN.Deleted != '1' AND ARC.ArcCode = #{SelectMenuId} AND C.ToItemID = Obj.ItemID AND C.CategoryCode in ('ST1', 'ST2') ), XBOLT_UCTE(ParentID, MyItemID, TREE_NM, SortNum) AS ( SELECT * FROM XBOLT_FILTER WITH (NOLOCK)
UNION ALL
SELECT ITM_U.FromItemID AS ParentID, ITM_U.ToItemID AS MyItemID, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE ISNULL(Obj.Identifier,'') + ' ' + ATR.PlainText END AS TREE_NM, C.SortNum FROM XBOLTADM.TB_ITEM ITM_U WITH (NOLOCK), XBOLT_UCTE UCTE, XBOLTADM.TB_ARC_FILTER ARCF WITH (NOLOCK), XBOLTADM.TB_ITEM Obj WITH (NOLOCK), XBOLTADM.TB_ITEM_ATTR ATR WITH (NOLOCK) , XBOLTADM.TB_ARC ARC WITH (NOLOCK), XBOLTADM.TB_ITEM C WITH (NOLOCK) WHERE ARCF.ArcCode = #{SelectMenuId} AND ITM_U.CategoryCode = 'ST1' AND ITM_U.Deleted != '1' AND ITM_U.ToItemID = UCTE.ParentID AND ITM_U.ToItemID = Obj.ItemID AND Obj.ClassCode not in (Select ItemClassCode FROM XBOLTADM.TB_ARC_FILTER_CLS WITH (NOLOCK) where ArcCode = #{SelectMenuId} and Included != 'Y' ) AND ITM_U.ToItemID = ATR.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType} AND ARC.ArcCode = #{SelectMenuId} AND C.ToItemID = Obj.ItemID AND C.CategoryCode in ('ST1', 'ST2')
) SELECT Distinct UCTE.ParentID AS PRE_TREE_ID, UCTE.MyItemID AS TREE_ID, 0 AS Level, UCTE.TREE_NM AS TREE_NM , UCTE.SortNum FROM XBOLT_UCTE UCTE
UNION
SELECT DISTINCT ICN.FromItemID AS PRE_TREE_ID, ICN.ToItemID AS TREE_ID, 0 AS Level, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE ISNULL(Obj.Identifier,'') + ' ' + ATR.PlainText END AS TREE_NM, C.SortNum FROM XBOLTADM.TB_ITEM ICN WITH (NOLOCK), XBOLTADM.TB_ARC_FILTER ARCF WITH (NOLOCK), XBOLTADM.TB_ITEM_ATTR ATR WITH (NOLOCK), XBOLTADM.TB_ITEM Obj WITH (NOLOCK) , XBOLTADM.TB_ARC ARC WITH (NOLOCK), XBOLTADM.TB_ITEM C WITH (NOLOCK), ( SELECT Distinct MYITM.ItemID FROM XBOLTADM.TB_MY_ITEM MYITM WITH (NOLOCK), XBOLTADM.TB_ITEM ITM WITH (NOLOCK) WHERE MYITM.MemberID = #{sessionUserId}
AND MYITM.AssignmentType = #{roleCategory}
) MYITM WHERE ICN.FromItemID = MYITM.ItemID AND ICN.ItemTypeCode in (select ConTypeCode from XBOLTADM.TB_ARC_FILTER WITH (NOLOCK) where ArcCode = #{SelectMenuId} ) AND ICN.ToItemID = ATR.ItemID AND ICN.ToItemID = Obj.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType} AND ICN.Deleted != '1' AND ARC.ArcCode = #{SelectMenuId} AND C.ToItemID = Obj.ItemID AND C.CategoryCode in ('ST1', 'ST2')
ORDER BY SortNum, TREE_NM ASC
ORDER BY TREE_NM ASC

WITH XBOLT_FILTER(ParentID, MyItemID, TREE_NM, ClassCode, ClassIcon) AS ( SELECT DISTINCT ICN.FromItemID AS ParentID, ICN.ToItemID AS MyItemID, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE ISNULL(Obj.Identifier,'') + ' ' + ATR.PlainText END AS TREE_NM , Obj.ClassCode, 'tree_' + TIC.Icon AS ClassIcon FROM XBOLTADM.TB_ITEM ICN, XBOLTADM.TB_ARC_FILTER ARCF, XBOLTADM.TB_ITEM Obj, XBOLTADM.TB_ITEM_ATTR ATR, XBOLTADM.TB_ARC ARC , XBOLTADM.TB_ITEM_CLASS TIC, ( SELECT ITM.ItemID FROM XBOLTADM.TB_ITEM ITM , XBOLTADM.TB_ITEM_CLASS CLS WHERE ITM.AuthorID = #{sessionUserId} AND ITM.Deleted != '1' AND CLS.ChangeMgt = 1 AND ITM.ClassCode = CLS.ItemClassCode
AND ITM.Status = #{itemStatus}
AND ITM.Status IN(${itemStatusList})
AND ITM.ClassCode IN (${classCodeList})
AND ITM.ItemTypeCode IN (${itemTypeCodeList})
) MYITM WHERE ICN.ToItemID = MYITM.ItemID AND ICN.CategoryCode = 'ST1' AND ICN.ToItemID = ATR.ItemID AND ICN.ToItemID = Obj.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType} AND ICN.Deleted != '1' AND ARC.ArcCode = #{SelectMenuId}
AND XBOLTADM.fn_CheckItemUpdated(ICN.ToItemID) = 'Y'
AND TIC.ItemClassCode = Obj.ClassCode ), XBOLT_UCTE(ParentID, MyItemID, TREE_NM, ClassCode, ClassIcon) AS ( SELECT * FROM XBOLT_FILTER
UNION ALL
SELECT CASE ITM_U.FromItemID WHEN '0' THEN '201' ELSE ITM_U.FromItemID END AS ParentID, ITM_U.ToItemID AS MyItemID, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE ISNULL(Obj.Identifier,'') + ' ' + ATR.PlainText END AS TREE_NM , Obj.ClassCode, 'tree_' + TIC.Icon AS ClassIcon FROM XBOLTADM.TB_ITEM ITM_U, XBOLT_UCTE UCTE, XBOLTADM.TB_ITEM Obj , XBOLTADM.TB_ITEM_ATTR ATR , XBOLTADM.TB_ARC ARC, XBOLTADM.TB_ITEM_CLASS TIC WHERE
ITM_U.CategoryCode = 'ST1' AND ITM_U.Deleted != '1' AND ITM_U.ToItemID = UCTE.ParentID AND ITM_U.ToItemID = Obj.ItemID AND ITM_U.ToItemID = ATR.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType} AND ARC.ArcCode = #{SelectMenuId} AND TIC.ItemClassCode = Obj.ClassCode
) SELECT Distinct UCTE.ParentID AS PRE_TREE_ID, UCTE.MyItemID AS TREE_ID, 0 AS Level , UCTE.TREE_NM AS TREE_NM , UCTE.ClassCode, UCTE.ClassIcon FROM XBOLT_UCTE UCTE
UNION
SELECT '0' AS PRE_TREE_ID, '201' AS TREE_ID, 0 AS Level, 'My Item' AS TREE_NM, 'CLX0001' AS ClassCode, '' AS ClassIcon
UNION
SELECT DISTINCT ICN.FromItemID AS ParentID, ICN.ToItemID AS MyItemID, 0 AS Level, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE ISNULL(Obj.Identifier,'') + ' ' + ATR.PlainText END AS TREE_NM, Obj.ClassCode, 'tree_' + TIC.Icon AS ClassIcon FROM XBOLTADM.TB_ITEM ICN, XBOLTADM.TB_ITEM Obj, XBOLTADM.TB_ITEM_ATTR ATR, XBOLTADM.TB_ARC ARC , XBOLTADM.TB_ITEM_CLASS TIC, ( SELECT ITM.ItemID FROM XBOLTADM.TB_ITEM ITM , XBOLTADM.TB_ITEM_CLASS CLS WHERE ITM.AuthorID = #{sessionUserId} AND ITM.Deleted != '1'
AND ITM.Status = #{itemStatus}
AND ITM.ClassCode IN (${classCodeList})
AND ITM.ItemTypeCode IN (${itemTypeCodeList})
) MYITM WHERE ICN.FromItemID = MYITM.ItemID AND ICN.CategoryCode = 'ST1' AND ICN.ToItemID = ATR.ItemID AND ICN.ToItemID = Obj.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType} AND ICN.Deleted != '1' AND ARC.ArcCode = #{SelectMenuId}
AND XBOLTADM.fn_CheckItemUpdated(ICN.ToItemID) = 'Y'
AND Obj.ClassCode = TIC.ItemClassCode AND Obj.AuthorID = #{sessionUserId}
ORDER BY TREE_NM ASC

WITH XBOLT_FILTER(ParentID, MyItemID, TREE_NM) AS ( SELECT DISTINCT ICN.FromItemID AS ParentID, ITM.ItemID AS MyItemID, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE ISNULL(ITM.Identifier,'') + ' ' + ATR.PlainText END AS TREE_NM FROM XBOLTADM.TB_ITEM ICN, XBOLTADM.TB_ARC ARC, XBOLTADM.TB_ITEM_ATTR ATR, ( SELECT Obj.ItemID, Obj.ClassCode , Obj.Identifier FROM XBOLTADM.TB_CHANGE_SET CNGS, XBOLTADM.TB_ITEM Obj
WHERE CNGS.Status = 'MOD' AND ( CNGS.AuthorID = #{sessionUserId} or CNGS.ChangeSetID in (Select Distinct ChangeSetID from XBOLTADM.TB_TASK where Actor = #{sessionUserId} ) ) AND CNGS.ItemID = Obj.ItemID ) ITM WHERE ICN.ToItemID = ITM.ItemID AND ICN.CategoryCode in ('ST1', 'ST2') AND ARC.ArcCode = #{SelectMenuId} AND ICN.Deleted != '1' AND ICN.ToItemID = ATR.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType}
AND (SELECT ChangeMgt FROM XBOLTADM.TB_ITEM_CLASS WHERE ItemClassCode = ITM.ClassCode) = 1
), XBOLT_LCTE(ParentID, MyItemID, TREE_NM) AS ( SELECT * FROM XBOLT_FILTER
UNION ALL
SELECT ITM_L.FromItemID AS ParentID, ITM_L.ToItemID AS MyItemID, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE ISNULL(Obj.Identifier,'') + ' ' + ATR.PlainText END AS TREE_NM FROM XBOLTADM.TB_ITEM ITM_L, XBOLT_LCTE LCTE, XBOLTADM.TB_ARC ARC, XBOLTADM.TB_ITEM Obj, XBOLTADM.TB_ITEM_ATTR ATR WHERE ARC.ArcCode = #{SelectMenuId} AND ITM_L.CategoryCode in ('ST1', 'ST2') AND ITM_L.Deleted != '1' AND ITM_L.FromItemID = LCTE.MyItemID AND ITM_L.ToItemID = Obj.ItemID AND Obj.ClassCode not in (Select ItemClassCode FROM XBOLTADM.TB_ARC_FILTER_CLS where ArcCode = #{SelectMenuId} and Included != 'Y' ) AND ITM_L.ToItemID = ATR.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType}
)
SELECT Distinct 0 AS PRE_TREE_ID, ITMTP.RootItemID AS TREE_ID, 0 AS Level, ATR.PlainText AS TREE_NM FROM XBOLT_FILTER , XBOLTADM.TB_ITEM_ATTR ATR , XBOLTADM.TB_ARC ARC, XBOLTADM.TB_ITEM Obj , XBOLTADM.TB_ITEM_TYPE ITMTP Where XBOLT_FILTER.MyItemID = Obj .ItemID AND obj.ItemTypeCode = ITMTP.ItemTypeCode AND ITMTP.RootItemID = ATR.ItemID AND ATR.LanguageID = #{sessionCurrLangType} AND ATR.AttrTypeCode = 'AT00001'
UNION
SELECT Distinct ITMTP.RootItemID AS PRE_TREE_ID, XBOLT_FILTER.ParentID AS TREE_ID, 0 AS Level, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE ISNULL(Obj.Identifier,'') + ' ' + ATR.PlainText END AS TREE_NM FROM XBOLT_FILTER , XBOLTADM.TB_ITEM_ATTR ATR , XBOLTADM.TB_ARC ARC, XBOLTADM.TB_ITEM Obj , XBOLTADM.TB_ITEM_TYPE ITMTP Where XBOLT_FILTER.ParentID = ATR.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType} AND ARC.ArcCode = #{SelectMenuId} AND XBOLT_FILTER.ParentID = Obj.ItemID AND Obj.ItemTypeCode = ITMTP.ItemTypeCode
UNION
SELECT Distinct LCTE.ParentID AS PRE_TREE_ID, LCTE.MyItemID AS TREE_ID, 0 AS Level, LCTE.TREE_NM AS TREE_NM FROM XBOLT_LCTE LCTE
ORDER BY TREE_NM ASC

WITH XBOLT_FILTER(ParentID, MyItemID, TREE_NM) AS ( SELECT DISTINCT ICN.FromItemID AS ParentID, ICN.ToItemID AS MyItemID, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE ISNULL(Obj.Identifier,'') + ' ' + ATR.PlainText END AS TREE_NM FROM XBOLTADM.TB_ITEM ICN, XBOLTADM.TB_ARC ARC, XBOLTADM.TB_ITEM Obj, XBOLTADM.TB_ITEM_ATTR ATR, ( SELECT TMR.ItemID FROM XBOLTADM.TB_TEAM_ROLE TMR , XBOLTADM.TB_ITEM ITM WHERE TMR.TeamID = #{sessionTeamId} AND TMR.ItemID = ITM.ItemID ) TMR WHERE ICN.ToItemID = TMR.ItemID AND ARC.ArcCode = #{SelectMenuId} AND ICN.CategoryCode = 'ST1' AND ICN.ItemTypeCode in (select ConTypeCode from XBOLTADM.TB_ARC_FILTER where ArcCode = #{SelectMenuId} ) AND ICN.ToItemID = Obj.ItemID AND ICN.ToItemID = ATR.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType} AND ICN.Deleted != '1'
), XBOLT_UCTE(ParentID, MyItemID, TREE_NM) AS ( SELECT * FROM XBOLT_FILTER
UNION ALL
