), XBOLT_LCTE(ParentID, MyItemID, TREE_NM) AS ( SELECT * FROM XBOLT_FILTER
UNION ALL
SELECT ITM_L.FromItemID AS ParentID, ITM_L.ToItemID AS MyItemID, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE ISNULL(Obj.Identifier,'') + ' ' + ATR.PlainText END AS TREE_NM FROM XBOLTADM.TB_ITEM ITM_L, XBOLT_LCTE LCTE, XBOLTADM.TB_ARC ARC, XBOLTADM.TB_ITEM Obj, XBOLTADM.TB_ITEM_ATTR ATR WHERE ARC.ArcCode = #{SelectMenuId} AND ITM_L.CategoryCode in ('ST1', 'ST2') AND ITM_L.Deleted != '1' AND ITM_L.FromItemID = LCTE.MyItemID AND ITM_L.ToItemID = Obj.ItemID AND Obj.ClassCode not in (Select ItemClassCode FROM XBOLTADM.TB_ARC_FILTER_CLS where ArcCode = #{SelectMenuId} and Included != 'Y' ) AND ITM_L.ToItemID = ATR.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType}
)
SELECT Distinct UCTE.ParentID AS PRE_TREE_ID, UCTE.MyItemID AS TREE_ID, 0 AS Level, UCTE.TREE_NM AS TREE_NM FROM XBOLT_UCTE UCTE
UNION
SELECT Distinct LCTE.ParentID AS PRE_TREE_ID, LCTE.MyItemID AS TREE_ID, 0 AS Level, LCTE.TREE_NM AS TREE_NM FROM XBOLT_LCTE LCTE
ORDER BY TREE_NM ASC

SELECT Distinct 0 AS PRE_TREE_ID , C.ItemID AS TREE_ID , C.Level, ATR.PlainText AS TREE_NM FROM XBOLTADM.TB_ITEM C, XBOLTADM.TB_ITEM_ATTR ATR, XBOLTADM.TB_ARC_FILTER ARCF WHERE C.ItemID in (Select RootItemID FROM XBOLTADM.TB_ARC_FILTER where ArcCode = #{SelectMenuId} ) AND C.ItemID = ATR.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType} AND C.Deleted != '1'
UNION SELECT Distinct C.FromItemID AS PRE_TREE_ID , C.ToItemID AS TREE_ID , Obj.Level, ATR.PlainText AS TREE_NM FROM XBOLTADM.TB_ITEM C, XBOLTADM.TB_ITEM_ATTR ATR, XBOLTADM.TB_ITEM Obj, XBOLTADM.TB_ARC_FILTER ARCF WHERE C.FromItemID != 0 AND ARCF.ArcCode = #{SelectMenuId} AND C.ItemTypeCode in (Select ConTypeCode FROM XBOLTADM.TB_ARC_FILTER where ArcCode = #{SelectMenuId} ) AND C.ToItemID = Obj.ItemID AND C.ToItemID = ATR.ItemID AND C.Deleted != '1' AND Obj.ClassCode not in (Select ItemClassCode FROM XBOLTADM.TB_ARC_FILTER_CLS where ArcCode = #{SelectMenuId} and Included != 'Y' ) AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType}
UNION SELECT DISTINCT Model.ItemID AS PRE_TREE_ID, Model.ModelID AS TREE_ID, 1 AS Level, (MDTXT.Name+'(' + DIC.Name + ')') AS TREE_NM FROM XBOLTADM.TB_ITEM ICN, XBOLTADM.TB_MODEL Model, XBOLTADM.TB_MODEL_TXT MDTXT , XBOLTADM.TB_DICTIONARY DIC
WHERE Model.ItemID = ICN.ItemID AND ICN.Deleted != '1' AND Model.Deleted != '1' AND Model.ModelID = MDTXT.ModelID AND DIC.TypeCode = Model.ModelTypeCode AND DIC.LanguageID = #{sessionCurrLangType} AND MDTXT.LanguageID = #{sessionCurrLangType}
ORDER BY TREE_NM ASC

SELECT CASE C.TeamID When #{rootTeamID} Then 0 Else C.ParentID END AS PRE_TREE_ID, C.TeamID AS TREE_ID , D.Name AS TREE_NM , SortNum FROM XBOLTADM.TB_TEAM C, XBOLTADM.TB_TEAM_TXT D WHERE C.TeamID = D.TeamID AND C.Deleted != '1' AND D.LanguageID = #{sessionCurrLangType}
AND C.ParentID != 0
ORDER BY SortNum, TREE_NM ASC

SELECT CASE C.TeamID When #{rootTeamID} Then 0 Else C.ParentID END AS PRE_TREE_ID, C.TeamID AS TREE_ID , D.Name AS TREE_NM , SortNum FROM XBOLTADM.TB_TEAM C, XBOLTADM.TB_TEAM_TXT D WHERE C.TeamID = D.TeamID AND C.ClientID = #{sessionClientId} AND C.Deleted != '1' AND D.LanguageID = #{sessionCurrLangType}
AND C.ParentID != 0
ORDER BY SortNum, TREE_NM ASC

WITH StaffTree AS ( SELECT '0' AS PRE_TREE_ID, '-1' AS TREE_ID, (SELECT NAME FROM XBOLTADM.TB_DICTIONARY WHERE TypeCode = 'LN00018' AND LanguageID = #{sessionCurrLangType}) AS TREE_NM, 0 AS SortNum UNION ALL
SELECT C.ParentID AS PRE_TREE_ID , C.TeamID AS TREE_ID , Convert(nvarchar(1000),D.Name) AS TREE_NM , c.SortNum FROM XBOLTADM.TB_TEAM C, XBOLTADM.TB_TEAM_TXT D WHERE C.TeamID = D.TeamID AND C.Deleted != '1' AND D.LanguageID = #{sessionCurrLangType} AND C.TeamID in ( SELECT DISTINCT OwnerTeamID FROM XBOLTADM.TB_ITEM WHERE Deleted != 1 AND CategoryCode = 'OJ'
AND ItemTypeCode = #{defItemTypeCode}
AND ClassCode in (Select ItemClassCode FROM XBOLTADM.TB_ARC_FILTER_CLS where ArcCode = #{SelectMenuId} and Included = 'Y' )
) AND TeamType Not In ( '1', '2') UNION ALL
SELECT CASE ss.ParentID When #{rootTeamID} Then '-1' Else ss.ParentID END AS PRE_TREE_ID, ss.TeamID AS TREE_ID, Convert(nvarchar(1000),DD.Name) AS TREE_NM , ss.SortNum FROM XBOLTADM.TB_TEAM ss INNER JOIN StaffTree t ON t.PRE_TREE_ID = ss.TeamID, XBOLTADM.TB_TEAM_TXT DD WHERE ss.TeamID = DD.TeamID AND ss.Deleted != '1' AND DD.LanguageID = #{sessionCurrLangType} AND ss.ParentID != 0 ) SELECT DISTINCT PRE_TREE_ID, TREE_ID, TREE_NM, SortNum FROM StaffTree ORDER BY SortNum , TREE_NM

/*menu_SQL.menuURL*/	
SELECT DISTINCT TOP 1 ISNULL(TMU.URL,'') AS URL
FROM XBOLTADM.TB_ITEM TI			
	INNER JOIN XBOLTADM.TB_MENU_ALLOC TM ON TI.ClassCode = TM.ClassCode
	
		 AND TM.ArcCode = #{ARCHITECTURE_CODE}
			
	INNER JOIN XBOLTADM.TB_MENU TMU ON TMU.MenuID = TM.MenuID	
WHERE TI.ItemID = #{ITEM_ID}

/*menu_SQL.getNotItemURL*/		
SELECT DISTINCT TOP 1 ISNULL(U.URL, '') AS URL
FROM XBOLTADM.TB_MENU_ALLOC U
WHERE U.ArcCode = #{ARCHITECTURE_CODE}
Order By URL DESC

Select Distinct Level
FROM XBOLTADM.TB_ITEM
WHERE ToItemID = #{MENU_ID}

SELECT CASE WHEN acr.DimTypeID IS NULL THEN acc.DefDimValueID ELSE acr.DimTypeID END DefDimValueID
FROM XBOLTADM.TB_ARC acr
	LEFT OUTER JOIN XBOLTADM.TB_ACCESS_RIGHT acc 
		ON acr.ArcCode = acc.ArcCode
		AND acc.MemberID = #{sessionUserId}
WHERE acr.ArcCode = #{SelectMenuId}

 
		Select TemplCode From XBOLTADM.TB_ACCESS_RIGHT
	   Where MemberID = #{sessionUserId}
	   And IsDefault = 1

WITH XBOLT_FILTER(ParentID, MyItemID, TREE_NM) AS ( SELECT DISTINCT ICN.FromItemID AS ParentID, ICN.ToItemID AS MyItemID, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE ISNULL(Obj.Identifier,'') + ' ' + ATR.PlainText END AS TREE_NM FROM XBOLTADM.TB_ITEM ICN, XBOLTADM.TB_ARC ARC, XBOLTADM.TB_ITEM Obj, XBOLTADM.TB_ARC_FILTER ARCF, XBOLTADM.TB_ITEM_ATTR ATR, ( SELECT Distinct ELE.Link , ELE.ClassCode FROM XBOLTADM.TB_MODEL MDL, XBOLTADM.TB_ARC_FILTER ARCF, XBOLTADM.TB_ARC_FILTER_CLS ARCFCL , XBOLTADM.TB_ELEMENT ELE WHERE ARCF.ArcCode = #{SelectMenuId} AND MDL.ItemID = ARCF.RootItemID and MDL.ModelTypeCode = #{masterModelType} and MTCategory = 'BAS' AND ELE.ModelID = MDL.ModelID AND ARCFCL.ArcCode = #{SelectMenuId} and ARCFCL.ItemClassCode = ELE.ClassCode and ARCFCL.Included ='Y'
) A WHERE ICN.ToItemID = A.Link AND ICN.ItemTypeCode in (Select ConTypeCode FROM XBOLTADM.TB_ARC_FILTER where ArcCode = #{SelectMenuId} ) AND ARC.ArcCode = #{SelectMenuId} AND ICN.ToItemID = Obj.ItemID AND ICN.Deleted != '1' AND ICN.ToItemID = ATR.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType}
), XBOLT_UCTE(ParentID, MyItemID, TREE_NM) AS ( SELECT * FROM XBOLT_FILTER
UNION ALL
SELECT ITM_U.FromItemID AS ParentID, ITM_U.ToItemID AS MyItemID, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE ISNULL(Obj.Identifier,'') + ' ' + ATR.PlainText END AS TREE_NM FROM XBOLTADM.TB_ITEM ITM_U, XBOLT_UCTE UCTE, XBOLTADM.TB_ARC ARC, XBOLTADM.TB_ARC_FILTER ARCF , XBOLTADM.TB_ITEM Obj, XBOLTADM.TB_ITEM_ATTR ATR WHERE ARCF.ArcCode = #{SelectMenuId} AND ARC.ArcCode = #{SelectMenuId} AND ITM_U.ItemTypeCode in (Select ConTypeCode FROM XBOLTADM.TB_ARC_FILTER where ArcCode = #{SelectMenuId} ) AND ITM_U.Deleted != '1' AND ITM_U.ToItemID = UCTE.ParentID AND ITM_U.ToItemID = Obj.ItemID AND Obj.ClassCode not in (Select ItemClassCode FROM XBOLTADM.TB_ARC_FILTER_CLS where ArcCode = #{SelectMenuId} and Included = 'N' ) AND ITM_U.ToItemID = ATR.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType}
), XBOLT_LCTE(ParentID, MyItemID, TREE_NM) AS ( SELECT * FROM XBOLT_FILTER
UNION ALL
SELECT ITM_L.FromItemID AS ParentID, ITM_L.ToItemID AS MyItemID, CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE ISNULL(Obj.Identifier,'') + ' ' + ATR.PlainText END AS TREE_NM FROM XBOLTADM.TB_ITEM ITM_L, XBOLT_LCTE LCTE, XBOLTADM.TB_ARC ARC, XBOLTADM.TB_ARC_FILTER ARCF, XBOLTADM.TB_ITEM Obj, XBOLTADM.TB_ITEM_ATTR ATR WHERE ARCF.ArcCode = #{SelectMenuId} AND ARC.ArcCode = #{SelectMenuId} AND ITM_L.ItemTypeCode in (Select ConTypeCode FROM XBOLTADM.TB_ARC_FILTER where ArcCode = #{SelectMenuId} ) AND ITM_L.Deleted != '1' AND ITM_L.FromItemID = LCTE.MyItemID AND ITM_L.ToItemID = Obj.ItemID AND Obj.ClassCode not in (Select ItemClassCode FROM XBOLTADM.TB_ARC_FILTER_CLS where ArcCode = #{SelectMenuId} and Included = 'N' ) AND ITM_L.ToItemID = ATR.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType} )
SELECT Distinct CASE ITM.ClassCode WHEN ARCFCL.ItemClassCode THEN ARCF.RootItemID ELSE UCTE.ParentID END AS PRE_TREE_ID, UCTE.MyItemID AS TREE_ID, 0 AS Level, UCTE.TREE_NM AS TREE_NM FROM XBOLT_UCTE UCTE , XBOLTADM.TB_ARC_FILTER_CLS ARCFCL , XBOLTADM.TB_ARC_FILTER ARCF , XBOLTADM.TB_ITEM ITM, XBOLTADM.TB_ITEM_CLASS ITMCLS Where ARCFCL.ArcCode = #{SelectMenuId} AND ARCF.ArcCode = #{SelectMenuId} AND ITM.ItemID = UCTE.MyItemID AND ITM.ClassCode = ITMCLS.ItemClassCode AND ARCFCL.IsSecondary = 'Y'
UNION
SELECT Distinct LCTE.ParentID AS PRE_TREE_ID, LCTE.MyItemID AS TREE_ID, 0 AS Level, LCTE.TREE_NM AS TREE_NM FROM XBOLT_LCTE LCTE
UNION
SELECT Distinct 0 AS PRE_TREE_ID , C.ItemID AS TREE_ID , C.Level , CASE ARC.WID WHEN '0' THEN ATR.PlainText ELSE C.Identifier + ' ' + ISNULL(ATR.PlainText, 'Untitled') END AS TREE_NM FROM XBOLTADM.TB_ITEM C Left Outer Join XBOLTADM.TB_ITEM_ATTR ATR on C.ItemID = ATR.ItemID AND ATR.AttrTypeCode = 'AT00001' AND ATR.LanguageID = #{sessionCurrLangType}, XBOLTADM.TB_ARC_FILTER ARCF, XBOLTADM.TB_ARC ARC , XBOLTADM.TB_DICTIONARY DIC WHERE C.ItemID in (Select RootItemID FROM XBOLTADM.TB_ARC_FILTER where ArcCode = #{SelectMenuId} ) AND C.Deleted != '1' AND ARC.ArcCode = #{SelectMenuId}
ORDER BY PRE_TREE_ID, TREE_NM ASC

Select TA.ArcCode, TD.Name As ArcName , ISNULL(TM.URL,'') AS URL, ISNULL(TA.VarFilter,TM.VarFilter) AS VarFilter , ISNULL(TA.Style,'csh_process') AS MenuStyle , ISNULL(TA.SortOption,'') As SortOption , ISNULL(TA.FilterType,'') AS FilterType , ISNULL(TF.StrType,'') AS StrType From XBOLTADM.TB_ARC TA Left Outer Join XBOLTADM.TB_MENU TM ON TM.MenuID = TA.MenuID Left Outer Join XBOLTADM.TB_TFILTER TF ON TF.TfilterCode = TA.FilterType Left Outer Join XBOLTADM.TB_DICTIONARY TD ON TD.TypeCode = TA.ArcCode And TD.LanguageID = #{languageID}
TA.ParentID = #{parentID}
TA.ParentID = (Select ParentID From XBOLTADM.TB_ARC Where ArcCode = #{subArcCode})
AND TA.ArcCode = #{arcCode}
Order By TA.SortNum, TA.ArcCode

SELECT VarFilter
	FROM XBOLTADM.TB_MENU
	WHERE MenuID = #{MenuID}

SELECT '0' AS PRE_TREE_ID , CAST(TDV.DimTypeID AS VARCHAR(20)) AS TREE_ID , 0 AS LEVEL , TIA.PlainText AS TREE_NM FROM XBOLTADM.TB_DIM_VALUE TDV INNER JOIN XBOLTADM.TB_ITEM_ATTR TIA ON TDV.DimTypeID = TIA.ItemID AND TIA.AttrTypeCode = 'AT00001' AND TIA.LanguageID = #{languageID}
INNER JOIN XBOLTADM.TB_ITEM_DIM TID ON TID.DimTypeID = TDV.DimTypeID AND TID.DimValueID = TDV.DimValueID AND TID.ItemID = #{s_itemID} AND TDV.Deleted != 1
LEFT OUTER JOIN XBOLTADM.TB_ITEM_ATTR TIA2 ON TIA2.ItemID = TIA.ItemID AND TIA2.AttrTypeCode = 'AT10000' AND TIA2.LanguageID = #{languageID} AND TIA2.ClassCode = 'CL10002' WHERE TDV.Deleted = 0 AND (TIA2.PlainText = #{itemTypeCode} OR TIA2.PlainText IS NULL) GROUP BY TDV.DimTypeID, TIA.PlainText UNION ALL SELECT CASE WHEN TDV.ParentID IS NULL THEN CAST(TDV.DimTypeID AS VARCHAR(20)) WHEN TDV.ParentID = '0' THEN CAST(TDV.DimTypeID AS VARCHAR(20)) ELSE CAST(TDV.DimTypeID AS VARCHAR(20))+'/'+TDV.ParentID END AS PRE_TREE_ID , CAST(TDV.DimTypeID AS VARCHAR(20))+'/'+TDV.DimValueID AS TREE_ID , TDV.LEVEL , TDVT.Name AS TREE_NM FROM XBOLTADM.TB_DIM_VALUE TDV
INNER JOIN XBOLTADM.TB_ITEM_DIM TID ON TID.DimTypeID = TDV.DimTypeID AND TID.DimValueID = TDV.DimValueID AND TID.ItemID = #{s_itemID}
LEFT OUTER JOIN XBOLTADM.TB_DIM_VALUE_TXT TDVT ON TDV.DimTypeID = TDVT.DimTypeID AND TDV.DimValueID = TDVT.DimValueID AND TDVT.LanguageID = #{languageID} WHERE TDV.Deleted = 0 GROUP BY TDV.DimTypeID,TDV.DimValueID, TDVT.Name, TDV.LEVEL, TDV.ParentID ORDER BY PRE_TREE_ID,TREE_ID,LEVEL

Select 
	#{parentID} AS PRE_TREE_ID,
	TIH.StrItemID AS TREE_ID, 
	TIH.L1ItemID,
	CASE ARC.WID WHEN '1' THEN  (CASE WHEN ARC.IDFilter IS NULL THEN ISNULL(TI2.Identifier,'') ELSE RIGHT(ISNULL(TI2.Identifier,''),ARC.IDFilter) END) + ' ' + ISNULL(TIA.PlainText, 'Untitled')				  			 
	  			  WHEN '2' THEN  ISNULL(TIA.PlainText, 'Untitled') + ' ' + ISNULL(TI2.Identifier,'')
	  			  WHEN '3' THEN  (CASE WHEN ARC.IDFilter IS NULL THEN ISNULL(TI.Identifier,TI2.Identifier) ELSE RIGHT(ISNULL(TI.Identifier,TI2.Identifier),ARC.IDFilter) END) + ' ' + ISNULL(TIA.PlainText, 'Untitled')
				  ELSE  ISNULL(TIA.PlainText, 'Untitled')  END AS TREE_NM,
	TIH.Level,
	TI.ClassCode AS ClassCode,
	TI.FromItemID, 
	TI.ToItemID,
	TI.StructureID
From XBOLTADM.TW_ITEM_STR_HIER TIH
Inner Join XBOLTADM.TB_ITEM TI ON TI.ItemID = TIH.StrItemID And TI.Deleted != 1
Inner Join XBOLTADM.TB_ITEM TI2 ON TI2.ItemID = TI.ToItemID And TI2.Deleted != 1
Left Outer Join XBOLTADM.TB_ITEM_ATTR TIA ON TIA.ItemID = TIH.ItemID And TIA.AttrTypeCode = 'AT00001' And TIA.LanguageID = #{languageID}
Left Outer Join XBOLTADM.TB_ARC ARC ON ARC.ArcCode = #{arcCode}
Where TIH.StructureID = #{structureID}
And TIH.ItemClassCode = #{classCode} 

	And TIH.L0ItemID = #{L0ItemID}


	And TIH.L1ItemID = #{L1ItemID}


	And TIH.L2ItemID = #{L2ItemID}


	And TIH.L3ItemID = #{L3ItemID}


	And TIH.L4ItemID = #{L4ItemID}


	And TIH.L5ItemID = #{L5ItemID}


	And TI2.ProjectID IN (${csrIDs})


	
		ORDER BY SortNum, Level, TREE_NM ASC
	
	
		ORDER BY Level, TREE_NM ASC

SELECT SortOption
FROM XBOLTADM.TB_ARC WITH (NOLOCK)
WHERE ArcCode = #{arcCode}

WITH RecursiveArc AS (
SELECT ArcCode, ParentID, DimTypeID, 1 AS Depth FROM xboltadm.TB_ARC WHERE ArcCode = #{arcCode}
UNION ALL
SELECT NextTA.ArcCode, NextTA.ParentID, NextTA.DimTypeID, Prev.Depth + 1 FROM xboltadm.TB_ARC NextTA INNER JOIN RecursiveArc Prev ON Prev.ParentID = NextTA.ArcCode WHERE Prev.ParentID IS NOT NULL AND Prev.ParentID != '0' ) SELECT Final.Level, Final.TargetName AS Name FROM ( SELECT (SELECT MAX(Depth) FROM RecursiveArc) - R.Depth + 1 AS Level, CAST(TD.Name AS NVARCHAR(MAX)) AS TargetName, 1 AS GroupOrder FROM RecursiveArc R LEFT OUTER JOIN xboltadm.TB_DICTIONARY TD ON TD.TypeCode = R.ArcCode AND TD.LanguageID = #{languageID}
UNION ALL
SELECT (SELECT MAX(Depth) FROM RecursiveArc) + 1 AS Level, TDVT.Name AS TargetName, 2 AS GroupOrder FROM RecursiveArc R INNER JOIN xboltadm.TB_DIM_VALUE_TXT TDVT ON R.DimTypeID != '0' AND R.DimTypeID IS NOT NULL AND TDVT.DimTypeID = R.DimTypeID AND TDVT.DimValueID = #{dimValueID} AND TDVT.LanguageID = #{languageID} WHERE R.Depth = 1
) AS Final ORDER BY GroupOrder ASC, Level ASC
